/**
 * Build / deploy presets as DATA — no vite / docker / fly dependencies.
 *
 * These mint the same config objects + template strings used by the shipped
 * games (project-mmo, deceive-me-daddy) so a new game doesn't re-derive them from
 * memory each time:
 *   - `viteBase`   → a partial vite config OBJECT (you spread it into defineConfig).
 *   - `flyToml`    → a fly.toml string (Colyseus-on-Fly: always-on when autoStop is
 *                    false, scale-to-zero when true).
 *   - `vercelJson` → a vercel.json string with SPA rewrites to /index.html.
 *   - `dockerfile` → a single-image pnpm-workspace Dockerfile string.
 *
 * THREE-FREE and dependency-free: pure data, unit-testable without any toolchain.
 */

export interface ViteBaseOptions {
  /** Dev server port. Default 5173 (vite's own default). */
  port?: number;
}

/** A minimal, structurally-typed view of the partial vite config we emit. */
export interface ViteBaseConfig {
  build: {
    target: string;
    sourcemap: boolean;
  };
  server: {
    port: number;
    host: boolean;
  };
  preview: {
    port: number;
  };
}

/**
 * A plain partial vite config object — spread it into your own `defineConfig`.
 * Targets es2022 (top-level await, modern syntax) and binds the dev + preview
 * servers to the same port, exposed on the LAN (`host: true`) for device testing.
 */
export function viteBase(opts: ViteBaseOptions = {}): ViteBaseConfig {
  const port = opts.port ?? 5173;
  return {
    build: {
      target: 'es2022',
      sourcemap: true,
    },
    server: {
      port,
      host: true,
    },
    preview: {
      port,
    },
  };
}

export interface FlyTomlOptions {
  /** Fly app name (the unique `app = "..."` slug). */
  app: string;
  /** internal_port the server listens on. Default 8080. */
  port?: number;
  /**
   * Scale-to-zero when idle. Default false → an always-on STATEFUL game server
   * (Colyseus in-memory rooms must never auto-sleep mid-match). Set true for a
   * stateless app to cut cost to near-zero.
   */
  autoStop?: boolean;
  /** Fly region slug. Default "iad". */
  region?: string;
}

/**
 * A fly.toml for a Colyseus-style single-machine game server, distilled from
 * project-mmo (always-on) and deceive-me-daddy (scale-to-zero). When `autoStop`
 * is false the machine never sleeps and keeps ≥1 running; when true it stops on
 * idle and wakes on the next connection.
 */
export function flyToml(opts: FlyTomlOptions): string {
  const port = opts.port ?? 8080;
  const region = opts.region ?? 'iad';
  const autoStop = opts.autoStop ?? false;

  const autoStopMachines = autoStop ? '"stop"' : '"off"';
  const minRunning = autoStop ? 0 : 1;

  return `# fly.toml — generated by game-kit presets.flyToml().
# Single stateful machine: serves the client + the game websocket on one port.
app = "${opts.app}"
primary_region = "${region}"

[build]
  dockerfile = "Dockerfile"

[http_service]
  internal_port = ${port}
  force_https = true
  auto_stop_machines = ${autoStopMachines}
  auto_start_machines = true
  min_machines_running = ${minRunning}

  # Stateful in-memory rooms: keep one match on one machine — never split traffic.
  [http_service.concurrency]
    type = "connections"
    soft_limit = 200
    hard_limit = 250

[[vm]]
  size = "shared-cpu-1x"
  memory = "512mb"
`;
}

export interface VercelJsonOptions {
  /** Emit SPA rewrites (all paths → /index.html). Default true. */
  spa?: boolean;
  /** Output directory of the built client. Default "dist". */
  outputDirectory?: string;
}

/**
 * A vercel.json for a static SPA client. With `spa` true (default) every route
 * rewrites to /index.html so client-side routing works on hard refresh, matching
 * the deceive-me-daddy deploy.
 */
export function vercelJson(opts: VercelJsonOptions = {}): string {
  const spa = opts.spa ?? true;
  const outputDirectory = opts.outputDirectory ?? 'dist';

  const config: {
    $schema: string;
    installCommand: string;
    outputDirectory: string;
    framework: null;
    rewrites?: { source: string; destination: string }[];
  } = {
    $schema: 'https://openapi.vercel.sh/vercel.json',
    installCommand: 'pnpm install --frozen-lockfile',
    outputDirectory,
    framework: null,
  };

  if (spa) {
    config.rewrites = [{ source: '/(.*)', destination: '/index.html' }];
  }

  return JSON.stringify(config, null, 2) + '\n';
}

export interface DockerfileOptions {
  /** Use pnpm (workspace) instead of npm. Default true. */
  pnpm?: boolean;
  /** Node base image tag. Default "22-slim". */
  node?: string;
  /** Port the server listens on / EXPOSEs. Default 8080. */
  port?: number;
}

/**
 * A single-stage Dockerfile string. With `pnpm` true (default) it follows the
 * deceive-me-daddy single-image pattern: install workspace deps first (cached),
 * copy source, build the client, run the server. Single-stage keeps the pnpm
 * node_modules symlink tree intact. With `pnpm` false it falls back to npm.
 */
export function dockerfile(opts: DockerfileOptions = {}): string {
  const usePnpm = opts.pnpm ?? true;
  const node = opts.node ?? '22-slim';
  const port = opts.port ?? 8080;

  if (usePnpm) {
    return `# Dockerfile — generated by game-kit presets.dockerfile() (pnpm workspace).
# Single-stage keeps the pnpm node_modules symlink tree intact.
FROM node:${node}

RUN npm install -g pnpm
WORKDIR /app

# 1) Install deps first so this layer caches unless a manifest/lockfile changes.
COPY pnpm-workspace.yaml pnpm-lock.yaml package.json ./
COPY . .
RUN pnpm install --frozen-lockfile

# 2) Build the client bundle.
RUN pnpm run build

# 3) Run the server (serves the built client + the websocket).
ENV NODE_ENV=production
ENV PORT=${port}
EXPOSE ${port}
CMD ["pnpm", "start"]
`;
  }

  return `# Dockerfile — generated by game-kit presets.dockerfile() (npm).
FROM node:${node}

WORKDIR /app

# 1) Install deps first so this layer caches unless package-lock.json changes.
COPY package.json package-lock.json ./
RUN npm ci

# 2) Copy source and build.
COPY . .
RUN npm run build

# 3) Run the server.
ENV NODE_ENV=production
ENV PORT=${port}
EXPOSE ${port}
CMD ["npm", "start"]
`;
}
